export function makeCounters(n: number): (() => number)[] {
  const fns: (() => number)[] = [];
  for (var i = 0; i < n; i++) {
    // BUG: var is function-scoped, all closures capture the same `i`
    fns.push(() => i);
  }
  return fns;
}

